# ── Package grouping helpers ──────────────────────────────────────────────────
PKG_GROUP_ORDER = [
    # Beyond Beer singles by oz
    "BB Singles 16oz", "BB Value Singles 16oz", "BB Singles 19oz", "BB Singles 22-24oz", "BB Singles 7oz", "BB Singles Other",
    # Core singles by oz
    "Core Singles 16oz", "Core Singles 24-25oz", "Core Singles 32oz", "Core Singles Other",
    # Core Plus singles by oz
    "Core Plus Singles 16oz", "Core Plus Singles 25oz", "Core Plus Singles 32oz", "Core Plus Singles Other",
    # Premium singles by oz
    "Premium Singles 16oz", "Premium Singles 22oz", "Premium Singles 24oz", "Premium Singles 32oz", "Premium Singles Other",
    # Super Premium singles by oz
    "Super Premium Singles 19oz", "Super Premium Singles 22oz", "Super Premium Singles Other",
    # Value singles by oz
    "Value Singles 16oz", "Value Singles 24-25oz", "Value Singles 40oz", "Value Singles Other",
    # Wine singles
    "Wine Singles 7oz",
    # Generic fallback
    "Singles", "Singles x4", "Singles x6", "Singles x8", "Singles x9",
    # Packs
    "6-packs", "8-packs", "12-packs", "15-packs", "18-packs", "24-packs (12oz)", "24-packs (7oz)",
    "3-packs (24oz)", "4-packs", "Wine/Other",
]

def pkg_group(package: str, wamp: str = "", brand: str = "") -> str:
    """Map a Package string (e.g. '1/16AL', '12/12C') to a display group."""
    p = str(package).strip()
    w = str(wamp).strip()
    b = str(brand).strip()
    # Singles: 1 unit — grouped by WAMP + oz size
    if p.startswith("1/"):
        size = p.split("/")[1].lower() if "/" in p else ""

        if w == "Beyond Beer":
            if size.startswith(("16c","16al")):
                if b in {"MD AB","Steel Reserve","Ritas","Seagram's Escapes"}:
                    return "BB Value Singles 16oz"
                return "BB Singles 16oz"
            if size.startswith("19"):              return "BB Singles 19oz"
            if size.startswith(("22","23","24b","24c")): return "BB Singles 22-24oz"
            if size.startswith("7"):               return "BB Singles 7oz"
            return "BB Singles Other"

        if w == "Core":
            if size.startswith(("16c","16al")):    return "Core Singles 16oz"
            if size.startswith(("24","25")):        return "Core Singles 24-25oz"
            if size.startswith("32"):              return "Core Singles 32oz"
            return "Core Singles Other"

        if w == "Core Plus":
            if size.startswith(("16c","16al")):    return "Core Plus Singles 16oz"
            if size.startswith("25"):              return "Core Plus Singles 25oz"
            if size.startswith("32"):              return "Core Plus Singles 32oz"
            return "Core Plus Singles Other"

        if w == "Premium":
            if size.startswith("16"):              return "Premium Singles 16oz"
            if size.startswith("22"):              return "Premium Singles 22oz"
            if size.startswith(("24","25")):        return "Premium Singles 24oz"
            if size.startswith("32"):              return "Premium Singles 32oz"
            return "Premium Singles Other"

        if w == "Super Premium":
            if size.startswith(("15","19")):        return "Super Premium Singles 19oz"
            if size.startswith("22"):              return "Super Premium Singles 22oz"
            return "Super Premium Singles Other"

        if w == "Value":
            if size.startswith("16"):              return "Value Singles 16oz"
            if size.startswith(("24","25")):        return "Value Singles 24-25oz"
            if size.startswith(("40","42")):        return "Value Singles 40oz"
            return "Value Singles Other"

        if w == "Wine":
            if size.startswith("7"):               return "Wine Singles 7oz"
            return "Wine/Other"

        return "Singles"

    # Multi-singles (e.g. x4, x6 packs of tallboys)
    if p.startswith(("1/16C x4","1/16C x6","1/16AL x4","1/25C x4","1/25C x6")):
        n = p.split("x")[-1].strip()
        return f"Singles x{n}" if n.isdigit() else "Singles"
    # Packs: qty/size format
    try:
        qty = int(p.split("/")[0])
    except (ValueError, IndexError):
        return "Wine/Other"
    if qty == 3:
        return "3-packs (24oz)"
    if qty == 4:
        return "4-packs"
    if qty == 6:
        return "6-packs"
    if qty == 8:
        return "8-packs"
    if qty == 9:
        return "Singles x9"
    if qty == 12:
        return "12-packs"
    if qty == 15:
        return "15-packs"
    if qty == 18:
        return "18-packs"
    if qty == 24:
        # Split 7oz (Coronita/Modelito style) from standard 12oz 24-packs
        size_part = p.split("/")[1].lower() if "/" in p else ""
        if size_part.startswith("7"):
            return "24-packs (7oz)"
        return "24-packs (12oz)"
    return "Wine/Other"


    """Build pricing DataFrame from PREFILLED_PRICING (Charleston data + survey CSV)."""
    rows = []
    chs_data = PREFILLED_PRICING.get("1 · Charleston", {})
    # Build UPC → product info map from CHS_UPC_DATA
    upc_info = {r[5]: r for r in CHS_UPC_DATA}
    for upc, chain_data in chs_data.items():
        info = upc_info.get(upc, None)
        if info is None:
            continue
        wamp, brand, product, wholesaler, package, _, _ = info
        for chain, prices in chain_data.items():
            retail   = prices.get("retail")
            two_for  = prices.get("two_for") or prices.get("ad_retail")
            two_disp = str(two_for) if two_for is not None else ""
            if retail is not None:
                rows.append((wamp, package, brand, product, upc, chain, retail, two_for, two_disp))
    df = pd.DataFrame(rows,
        columns=["Category","Package","Brand","Product","UPC","Competitor","Single","TwoFor","TwoFor_Display"])
    df["Market"]   = "1 · Charleston"
    df["Format"]   = df["Package"].apply(
        lambda p: "Singles" if str(p).startswith(("1/", "3/")) else "Packages"
    )
    df["PkgGroup"] = df["Package"].apply(pkg_group)
    return df


