@st.cache_data(show_spinner=False)
def compute_chain_deviation(survey_df_json: str) -> str:
    """Cache per-chain deviation summary. Returns JSON string."""
    import io
    df = pd.read_json(io.StringIO(survey_df_json), orient="split")
    if df.empty:
        return "{}"
    overall = df["Single"].mean()
    grp  = df.groupby("Competitor")["Single"].agg(["mean","count"]).round(2)
    grp.columns = ["Avg Single Price ($)", "N"]
    grp["Avg Deviation from Market ($)"] = (grp["Avg Single Price ($)"] - overall).round(2)
    grp = grp.reset_index().rename(columns={"Competitor": "Chain"})
    return grp.to_json(orient="split")

@st.cache_data(show_spinner=False)
def compute_product_pivot(survey_df_json: str) -> str:
    """Cache product-level pivot for gap analysis. Returns JSON string."""
    import io
    df = pd.read_json(io.StringIO(survey_df_json), orient="split")
    if df.empty:
        return "{}"
    pivot = df.pivot_table(
        index=["WAMP","PkgGroup","Product"], columns="Competitor",
        values="Single", aggfunc="mean"
    ).round(2)
    pivot.columns.name = None
    return pivot.to_json(orient="split")

@st.cache_data(show_spinner=False)
def compute_presales_pivot(survey_df_json: str) -> str:
    """Cache pre-sales WAMP/PkgGroup pivot. Returns JSON string."""
    import io
    df = pd.read_json(io.StringIO(survey_df_json), orient="split")
    if df.empty:
        return "{}"
    grp   = df.groupby(["WAMP","PkgGroup","Competitor"])["Single"].mean().round(2)
    pivot = grp.unstack("Competitor")
    pivot.columns.name = None
    return pivot.to_json(orient="split")


@st.cache_data(show_spinner=False)
def _make_barcode_b64(upc_str: str, height_px: int = 80) -> str | None:
    """Cached UPC-A / EAN-13 barcode image generator."""
    try:
        from PIL import Image as PilImage
        from barcode import UPCA, EAN13
        from barcode.writer import ImageWriter as _IW
        from io import BytesIO as _BIO
        import base64 as _b64mod
        upc_str = str(upc_str).strip().split(".")[0]
        writer  = _IW()
        bc_obj  = EAN13(upc_str[:12], writer=writer) if len(upc_str) >= 13 else UPCA(upc_str[:11], writer=writer)
        buf = _BIO()
        bc_obj.write(buf, options={"write_text": True, "module_height": 15.0,
                                   "module_width": 0.8, "quiet_zone": 6.0, "dpi": 200,
                                   "background": "white", "foreground": "black",
                                   "font_size": 8, "text_distance": 4})
        buf.seek(0)
        img    = PilImage.open(buf)
        aspect = img.width / img.height
        img    = img.resize((int(height_px * aspect), height_px), PilImage.LANCZOS)
        out    = _BIO()
        img.save(out, format="PNG", optimize=True)
        out.seek(0)
        return _b64mod.b64encode(out.read()).decode()
    except Exception:
        return None

@st.cache_data(show_spinner=False)
def _make_barcode_b64_from_font(code_str: str, height_px: int = 80) -> str | None:
    """Cached IDAutomation font-string → UPC-A barcode image."""
    import re as _re2
    _dmap = {c: str(i % 10) for i, c in enumerate("KLMNOPQRSTklmnopqrst")}
    try:
        enc = str(code_str).strip()
        if "*" not in enc:
            return None
        pp, sp = enc.split("*", 1)
        sp = sp[:-2]
        if len(pp) < 3:
            return None
        ld = ord(pp[2]) - 97
        if not (0 <= ld <= 9):
            return None
        upc = str(ld) + _re2.sub(r"[^0-9]", "", pp[3:]) + "".join(_dmap.get(c, "") for c in sp)
        if len(upc) != 12:
            return None
        return _make_barcode_b64(upc, height_px)
    except Exception:
        return None

@st.cache_resource
def _get_counties_geojson():
    """Fetch SC+GA county GeoJSON once per process — never re-fetched."""
    try:
        import requests as _req
        _geo = _req.get(
            "https://raw.githubusercontent.com/plotly/datasets/master/geojson-counties-fips.json",
            timeout=10
        ).json()
        _geo["features"] = [f for f in _geo["features"]
                             if f["properties"]["STATE"] in ("45", "13")]
        _name_fips = {
            (f["properties"]["NAME"] + " County").lower(): f["id"]
            for f in _geo["features"]
        }
        return _geo, _name_fips
    except Exception:
        return None, {}

@st.cache_data(show_spinner=False)
def _compute_county_flags(survey_json: str, name_to_fips_json: str, mkt_label: str, threshold_val: float) -> dict:
    """Compute per-county pricing flag counts. Cached by survey data + market + threshold."""
    import json, io
    df    = pd.read_json(io.StringIO(survey_json), orient="split")
    n2f   = json.loads(name_to_fips_json)
    if df.empty or not n2f:
        return {}

    # Determine SCP and competitor wholesaler for this market dynamically
    _SCP       = "Southern Crown Partners"
    _mkt_ws    = MARKET_WHOLESALERS.get(mkt_label, [_SCP])
    _comp_ws   = [w for w in _mkt_ws if w != _SCP]

    # Build chain → count by flagging any chain where SCP prices above competitor
    # When no known competitor wholesaler, flag chains where retail price > market avg
    _chain_flag_counts = {}

    if _comp_ws:
        # Use wholesaler-based comparison (same as heatmap logic)
        if "Parent Chain" in df.columns and "Retail $" in df.columns and "Wholesaler" in df.columns:
            _scp_rows  = df[df["Wholesaler"] == _SCP]
            _comp_rows = df[df["Wholesaler"].isin(_comp_ws)]
            for _chain in df["Parent Chain"].dropna().unique():
                _scp_prices  = _scp_rows[_scp_rows["Parent Chain"]  == _chain]["Retail $"].dropna()
                _comp_prices = _comp_rows[_comp_rows["Parent Chain"] == _chain]["Retail $"].dropna()
                if not _scp_prices.empty and not _comp_prices.empty:
                    if float(_scp_prices.mean()) - float(_comp_prices.mean()) >= threshold_val:
                        _chain_flag_counts[_chain] = _chain_flag_counts.get(_chain, 0) + 1
    else:
        # No competitor wholesaler — flag chains priced above market average
        if "Parent Chain" in df.columns and "Retail $" in df.columns:
            _mkt_avg = df["Retail $"].mean()
            for _chain in df["Parent Chain"].dropna().unique():
                _chain_avg = df[df["Parent Chain"] == _chain]["Retail $"].mean()
                if _chain_avg - _mkt_avg >= threshold_val:
                    _chain_flag_counts[_chain] = _chain_flag_counts.get(_chain, 0) + 1
    # Map chain → county → fips → count
    _acct  = get_account_df()
    _mname = mkt_label.split(" · ")[1] if " · " in mkt_label else mkt_label
    _acct  = _acct[_acct.get("market", pd.Series(dtype=str)).str.contains(_mname, case=False, na=False)]              if "market" in _acct.columns else _acct
    _valid = set(_acct["county"].str.strip().str.lower().dropna().unique()) if "county" in _acct.columns else set()
    _flags = {}
    for _, _ar in _acct.iterrows():
        _ch = str(_ar.get("parent_chain", ""))
        _co = str(_ar.get("county", "")).strip().lower()
        if _ch in _chain_flag_counts and _co and _co in _valid:
            _fips = n2f.get(_co)
            if _fips:
                _flags[_fips] = _flags.get(_fips, 0) + _chain_flag_counts[_ch]
    return _flags

@st.cache_data
def load_data():
    """Build the main pricing DataFrame from MARKETS (sc_*_data / ga_data)."""
    frames = []
    _single_pats = ('1/7','1/16','1/19','1/22','1/23','1/24','1/25','1/32','1/40','1/42','1/500')
    for market_name, (mkt_data, competitors) in MARKETS.items():
        for row in mkt_data:
            category, product, our_price = row[0], row[1], row[2]
            for ci, comp in enumerate(competitors):
                comp_price = row[3 + ci] if (3 + ci) < len(row) else None
                if comp_price is None:
                    continue
                frames.append({
                    "Category":     category,
                    "Product":      product,
                    "Competitor":   comp,
                    "Our Price":    our_price,
                    "Comp Price":   comp_price,
                    "Market":       market_name,
                    "Format":       "Singles" if any(p in product for p in _single_pats) else "Packages",
                    "Package":      None,
                    "Brand":        None,
                    "PkgGroup":     None,
                    "Market Avg":   None,
                    "Diff to Comp": None,
                    "Diff to Avg":  None,
                })

    combined = pd.DataFrame(frames) if frames else pd.DataFrame(
        columns=["Category","Product","Competitor","Our Price","Comp Price",
                 "Market","Format","Package","Brand","PkgGroup",
                 "Market Avg","Diff to Comp","Diff to Avg"]
    )
    if not combined.empty:
        combined["Market Avg"]   = combined.groupby(["Product","Market"])["Comp Price"].transform("mean")
        combined["Diff to Comp"] = combined.apply(
            lambda r: round(r["Our Price"] - r["Comp Price"], 2)
                      if pd.notna(r["Our Price"]) and pd.notna(r["Comp Price"]) else None, axis=1)
        combined["Diff to Avg"]  = combined.apply(
            lambda r: round(r["Our Price"] - r["Market Avg"], 2)
                      if pd.notna(r["Our Price"]) and pd.notna(r["Market Avg"]) else None, axis=1)
    return combined

