        import re as _re_mkt
        _sfx_match = _re_mkt.search(r'\(([A-Z]+)\)$', _sel_store_input)
        _sfx = _sfx_match.group(1) if _sfx_match else ""
        _CODE_TO_MARKET = {v: k for k, v in MARKET_CODES.items() if v}
        _derived_market  = _CODE_TO_MARKET.get(_sfx, "All Markets")
